SELECT c.id, c.name, c.source, s.id as survey_id
FROM customers c 
JOIN surveys s ON s.customer_id = c.id
JOIN share_links sl ON sl.survey_id = s.id
WHERE sl.token = 'vn3b_k7IF6mM8DU4jFMbNhH1Z6zgv9yT';

SELECT st.id, st.name, st.source_id, src.name as source_name
FROM survey_templates st
JOIN sources src ON src.id = st.source_id;

SELECT id, name FROM sources WHERE name LIKE '%Gulf%' OR name LIKE '%gulf%';

